module top_module(
  input clk,
  input reset,
  input load,
  input [7:0] data,
  output reg [7:0] out
);reg [7:0] shift_reg;

always @ (posedge clk or negedge reset) begin
  if (reset == 0) begin
    shift_reg <= 8'b0;
  end else if (load == 0) begin
    shift_reg <= data;
  end else begin
    shift_reg <= {shift_reg[6:0], shift_reg[7]};
  end
end

assign out = shift_reg;

endmodule
